package org.example.controller;
import org.example.model.entity.User; import org.example.model.enums.UserRole; import org.example.service.UserService; import org.junit.jupiter.api.Test; import org.springframework.test.web.servlet.MockMvc; import org.springframework.test.web.servlet.setup.MockMvcBuilders; import java.util.List; import static org.mockito.Mockito.*; import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.get; import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;
class UserControllerTest { @Test void shouldReturnAllUsers() throws Exception { UserService service=mock(UserService.class); User user=new User(); user.setId(1L); user.setName("Иван"); user.setEmail("ivan@example.com"); user.setRole(UserRole.ROLE_USER); when(service.getAllUsers()).thenReturn(List.of(user)); MockMvc mvc=MockMvcBuilders.standaloneSetup(new UserController(service)).build(); mvc.perform(get("/users/all")).andExpect(status().isOk()).andExpect(jsonPath("$[0].name").value("Иван")); } }
